            "recipientId" : "6243582",
            "reactions" : [ ],
            "urls" : [ ],
            "text" : "I know, but I always assume people forget who I am, haha. Hes got a background in web development. Hes looking into either front end or full stack web development.",
            "mediaUrls" : [ ],
            "senderId" : "58872733",
